 1	import * as React from 'react';
 2	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 3	import { Text, TextVariants } from '@patternfly/react-core';
 4	import { ExternalLinkAltIcon } from '@patternfly/react-icons';
 5	
 6	export const ViewDocumentation: React.FC<ViewDocumentationProps> = ({
 7	  doclink,
 8	  text,
 9	  padding = '15px 10px',
10	  hideDocLink,
11	}) => {
12	  const { t } = useCustomTranslation();
13	
14	  if (!doclink || hideDocLink) return null;
15	
16	  return (
17	    <Text
18	      component={TextVariants.a}
19	      isVisitedLink
20	      href={doclink}
21	      target="_blank"
22	      style={{
23	        cursor: 'pointer',
24	        display: 'inline-block',
25	        padding: padding,
26	        fontSize: '14px',
27	      }}
28	    >
29	      {text || t('View documentation')} <ExternalLinkAltIcon />
30	    </Text>
31	  );
32	};
33	
34	type ViewDocumentationProps = {
35	  doclink: string;
36	  text?: string;
37	  padding?: string;
38	  hideDocLink?: boolean;
39	};

